$slides = Get-ChildItem "$TmpDir\ppt\slides" -Filter 'slide*.xml' | Sort-Object { [int]($_.BaseName -replace 'slide','') }
foreach ($s in $slides) {
    $content = Get-Content $s.FullName -Raw -Encoding UTF8
    $ms = [regex]::Matches($content, '<a:t[^>]*>([^<]+)</a:t>')
    $texts = @()
    foreach ($m in $ms) { $texts += $m.Groups[1].Value }
    $joined = $texts -join '|'
    Write-Output "=== SLIDE $($s.BaseName) ==="
    Write-Output $joined
    Write-Output ""
}
